def validate(args, output):
    req_skills, people = args[0], args[1]
    if not isinstance(output, list):
        return False
    idx = {s: i for i, s in enumerate(req_skills)}
    full = (1 << len(req_skills)) - 1
    pmask = []
    for p in people:
        m = 0
        for s in p:
            if s in idx:
                m |= 1 << idx[s]
        pmask.append(m)
    # output must be valid indices, distinct, covering all skills
    seen = set()
    cover = 0
    for i in output:
        if not isinstance(i, int) or i < 0 or i >= len(people):
            return False
        if i in seen:
            return False
        seen.add(i)
        cover |= pmask[i]
    if cover != full:
        return False
    # minimality: compute the true minimum team size via bitmask DP
    INF = float('inf')
    dp = [INF] * (full + 1)
    dp[0] = 0
    for state in range(full + 1):
        if dp[state] == INF:
            continue
        for m in pmask:
            ns = state | m
            if dp[ns] > dp[state] + 1:
                dp[ns] = dp[state] + 1
    return len(output) == dp[full]

