function validate(args, output) {
    const reqSkills = args[0], people = args[1];
    if (!Array.isArray(output)) return false;
    const idx = new Map();
    reqSkills.forEach((s, i) => idx.set(s, i));
    const full = (1 << reqSkills.length) - 1;
    const pmask = people.map(p => {
        let m = 0;
        for (const s of p) if (idx.has(s)) m |= 1 << idx.get(s);
        return m;
    });
    const seen = new Set();
    let cover = 0;
    for (const i of output) {
        if (!Number.isInteger(i) || i < 0 || i >= people.length) return false;
        if (seen.has(i)) return false;
        seen.add(i);
        cover |= pmask[i];
    }
    if (cover !== full) return false;
    const INF = Infinity;
    const dp = new Array(full + 1).fill(INF);
    dp[0] = 0;
    for (let state = 0; state <= full; state++) {
        if (dp[state] === INF) continue;
        for (const m of pmask) {
            const ns = state | m;
            if (dp[ns] > dp[state] + 1) dp[ns] = dp[state] + 1;
        }
    }
    return output.length === dp[full];
}

