class Solution:
    def smallestSufficientTeam(self, req_skills, people):
        # independent: increase the allowed team size k from 0 upward and, for
        # each k, search for the lexicographically smallest k-subset that covers
        # all skills. The first k that yields one is the minimum team size, and
        # the subset found is canonical (lex-smallest).
        import itertools
        idx = {s: i for i, s in enumerate(req_skills)}
        full = (1 << len(req_skills)) - 1
        pmask = []
        for p in people:
            m = 0
            for s in p:
                if s in idx:
                    m |= 1 << idx[s]
            pmask.append(m)
        n = len(people)
        for k in range(0, n + 1):
            for combo in itertools.combinations(range(n), k):
                cover = 0
                for i in combo:
                    cover |= pmask[i]
                if cover == full:
                    return list(combo)
        return []

