class Solution:
    def smallestSufficientTeam(self, req_skills, people):
        idx = {s: i for i, s in enumerate(req_skills)}
        full = (1 << len(req_skills)) - 1
        pmask = []
        for p in people:
            m = 0
            for s in p:
                if s in idx:
                    m |= 1 << idx[s]
            pmask.append(m)
        INF = float('inf')
        size = [INF] * (full + 1)
        size[0] = 0
        for state in range(full + 1):
            if size[state] == INF:
                continue
            for m in pmask:
                ns = state | m
                if size[state] + 1 < size[ns]:
                    size[ns] = size[state] + 1
        target = size[full]
        n = len(people)
        def dfs(start, state, chosen):
            if state == full:
                return list(chosen)
            if len(chosen) >= target:
                return None
            for i in range(start, n):
                chosen.append(i)
                got = dfs(i + 1, state | pmask[i], chosen)
                chosen.pop()
                if got is not None:
                    return got
            return None
        return dfs(0, 0, [])

