var smallestSufficientTeam = function(req_skills, people) {
    const idx = new Map();
    req_skills.forEach((s, i) => idx.set(s, i));
    const full = (1 << req_skills.length) - 1;
    const pmask = people.map(p => {
        let m = 0;
        for (const s of p) if (idx.has(s)) m |= 1 << idx.get(s);
        return m;
    });
    const INF = Infinity;
    const size = new Array(full + 1).fill(INF);
    size[0] = 0;
    for (let state = 0; state <= full; state++) {
        if (size[state] === INF) continue;
        for (const m of pmask) {
            const ns = state | m;
            if (size[state] + 1 < size[ns]) size[ns] = size[state] + 1;
        }
    }
    const target = size[full];
    const n = people.length;
    function dfs(start, state, chosen) {
        if (state === full) return chosen.slice();
        if (chosen.length >= target) return null;
        for (let i = start; i < n; i++) {
            chosen.push(i);
            const got = dfs(i + 1, state | pmask[i], chosen);
            chosen.pop();
            if (got !== null) return got;
        }
        return null;
    }
    return dfs(0, 0, []);
};
